import{_ as l,c as t,o as s,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.41: Multiple Fixes and Improvements, Chinese Localization Enhanced","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.41.md","filePath":"en/changelog/v1.1.41.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.41.md"};function n(o,a,u,d,h,p){return s(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-41-multiple-fixes-and-improvements-chinese-localization-enhanced" tabindex="-1">v1.1.41: Multiple Fixes and Improvements, Chinese Localization Enhanced <a class="header-anchor" href="#v1-1-41-multiple-fixes-and-improvements-chinese-localization-enhanced" aria-label="Permalink to “v1.1.41: Multiple Fixes and Improvements, Chinese Localization Enhanced”">​</a></h1><p><strong>Release Date</strong>: January 29, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update fixes multiple issues, improves Chinese localization experience, and enhances tool functionality and responsiveness.</p><hr><h2 id="bug-fix-kimi-k2-5-model-parameter-issue" tabindex="-1">Bug Fix: Kimi K2.5 Model Parameter Issue <a class="header-anchor" href="#bug-fix-kimi-k2-5-model-parameter-issue" aria-label="Permalink to “Bug Fix: Kimi K2.5 Model Parameter Issue”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>The maxOutputTokens parameter for Kimi K2.5 model was incorrectly hardcoded to undefined, causing problems on some inference providers.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @ideallove&#39;s fix, the maxOutputTokens parameter can now be set correctly, and the Kimi K2.5 model works on all providers.</p><hr><h2 id="bug-fix-cache-collision" tabindex="-1">Bug Fix: Cache Collision <a class="header-anchor" href="#bug-fix-cache-collision" aria-label="Permalink to “Bug Fix: Cache Collision”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>SDK cache keys didn&#39;t include provider ID, potentially causing cache collisions between different providers.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @saba-ch&#39;s fix, cache keys now include provider ID, ensuring different providers&#39; caches don&#39;t interfere with each other.</p><hr><h2 id="bug-fix-chinese-localization-issue" tabindex="-1">Bug Fix: Chinese Localization Issue <a class="header-anchor" href="#bug-fix-chinese-localization-issue" aria-label="Permalink to “Bug Fix: Chinese Localization Issue”">​</a></h2><h3 id="previous-issue-2" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-2" aria-label="Permalink to “Previous Issue”">​</a></h3><ul><li>Chinese punctuation not displaying correctly</li><li>Missing Chinese translation keys falling back to English</li></ul><h3 id="current-status-2" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-2" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @MaxMiksa&#39;s fix:</p><ul><li>Punctuation now displays correctly</li><li>Missing Chinese translation keys have been filled, ensuring fully localized interface</li></ul><hr><h2 id="new-feature-file-tab-improvements" tabindex="-1">New Feature: File Tab Improvements <a class="header-anchor" href="#new-feature-file-tab-improvements" aria-label="Permalink to “New Feature: File Tab Improvements”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>File tabs now automatically scroll to visible area when opened</li><li>Support mouse wheel scrolling for file tabs</li></ul><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><p>When there are too many file tabs:</p><ul><li>Opening a file automatically scrolls to that tab</li><li>Use mouse wheel to quickly browse all tabs</li></ul><hr><h2 id="new-feature-abortsignal-support" tabindex="-1">New Feature: AbortSignal Support <a class="header-anchor" href="#new-feature-abortsignal-support" aria-label="Permalink to “New Feature: AbortSignal Support”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Ripgrep.files() and GlobTool now support AbortSignal for better control over file search operations.</p><h3 id="how-to-use-1" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to use?”">​</a></h3><p>Pass AbortSignal when searching files to cancel search operations when needed, improving control.</p><hr><h2 id="new-feature-audio-file-support" tabindex="-1">New Feature: Audio File Support <a class="header-anchor" href="#new-feature-audio-file-support" aria-label="Permalink to “New Feature: Audio File Support”">​</a></h2><h3 id="what-was-updated-2" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-2" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now allows loading small audio files using data: URLs in Content Security Policy.</p><h3 id="impact-on-you" tabindex="-1">Impact on You <a class="header-anchor" href="#impact-on-you" aria-label="Permalink to “Impact on You”">​</a></h3><p>Can use audio files in the interface without an external server, improving self-containment.</p><hr><h2 id="bug-fix-settings-responsiveness" tabindex="-1">Bug Fix: Settings Responsiveness <a class="header-anchor" href="#bug-fix-settings-responsiveness" aria-label="Permalink to “Bug Fix: Settings Responsiveness”">​</a></h2><h3 id="previous-issue-3" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-3" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Settings interface responsiveness was not good enough on mobile or small screen devices.</p><h3 id="current-status-3" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-3" aria-label="Permalink to “Current Status”">​</a></h3><p>Improved settings interface responsiveness, now displays well on various screen sizes.</p><hr><h2 id="bug-fix-dialog-alignment" tabindex="-1">Bug Fix: Dialog Alignment <a class="header-anchor" href="#bug-fix-dialog-alignment" aria-label="Permalink to “Bug Fix: Dialog Alignment”">​</a></h2><h3 id="previous-issue-4" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-4" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Element alignment and spacing in dialogs were incorrect.</p><h3 id="current-status-4" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-4" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed alignment and spacing issues, dialogs are now more aesthetically pleasing and usable.</p><hr><h2 id="bug-fix-katex-math-formulas" tabindex="-1">Bug Fix: KaTeX Math Formulas <a class="header-anchor" href="#bug-fix-katex-math-formulas" aria-label="Permalink to “Bug Fix: KaTeX Math Formulas”">​</a></h2><h3 id="previous-issue-5" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-5" aria-label="Permalink to “Previous Issue”">​</a></h3><p>KaTeX inline math formulas displayed abnormally when followed by punctuation.</p><h3 id="current-status-5" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-5" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed this issue. Math formulas can now be followed by punctuation normally.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using Kimi K2.5 model</td><td>✅ Highly recommended (critical fix)</td></tr><tr><td>Using Chinese interface</td><td>✅ Recommended upgrade (localization improvements)</td></tr><tr><td>Using Desktop version</td><td>✅ Recommended upgrade (multiple improvements)</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',65),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure variants for Copilot models work with maxTokens being set</li><li>Fixed maxOutputTokens being accidentally hardcoded to undefined which caused kimi-k2.5 issues on some inference providers (@ideallove)</li><li>Include provider ID in SDK cache key to prevent cache collisions (@saba-ch)</li><li>Allow media-src data: URL for small audio files in Content Security Policy (@tanapok)</li><li>Update experimental environment variables in CLI documentation (@bbabou)</li><li>Add ctx.abort to grep tool</li><li>Add AbortSignal support to Ripgrep.files() and GlobTool (@goniz)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Make settings more responsive for mobile and small web/desktop (@DNGriffin)</li><li>Fixed type errors in app package (@Brendonovich)</li><li>Auto scroll to file tabs on open and enable mouse wheel scrolling (@alexyaroshuk)</li><li>Remove duplicate keys causing TypeScript failures (@eXamadeus)</li><li>Normalize Chinese punctuation for Chinese UI (@MaxMiksa)</li><li>Fill missing Chinese translation keys to avoid English fallback (@MaxMiksa)</li><li>Fix alignment and padding in dialogs (@alexyaroshuk)</li></ul><p><strong>Thank you to 12 community contributors:</strong></p><p>@R44VC0RP:</p><ul><li>fix(script): remove highlights template from release notes (#11052)</li></ul><p>@zerone0x:</p><ul><li>fix(ui): allow KaTeX inline math to be followed by punctuation (#11033)</li></ul><p>@alexyaroshuk:</p><ul><li>fix(app): alignment and padding in dialogs (#10866)</li><li>fix(app): file tabs - auto scroll on open &amp; scroll via mouse wheel (#11070)</li></ul><p>@MaxMiksa:</p><ul><li>fix(app): fill missing zh keys to avoid English fallback (#10841)</li><li>fix(opencode): normalize zh punctuation for Chinese UI (#10842)</li><li>fix(ui): improve zh duration display formatting (#10844)</li></ul><p>@goniz:</p><ul><li>fix(opencode): add AbortSignal support to Ripgrep.files() and GlobTool (#10833)</li></ul><p>@eXamadeus:</p><ul><li>fix(typescript errors): remove duplicate keys causing typescript failures (#11071)</li></ul><p>@Brendonovich:</p><ul><li>fix(app): types</li></ul><p>@bbabou:</p><ul><li>docs: update experimental environment variables in CLI docs (#11030)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): make settings more responsive for mobile and small web/desktop (#10775)</li></ul><p>@tanapok:</p><ul><li>fix(opencode): allow media-src data: URL for small audio files (#11082)</li></ul><p>@saba-ch:</p><ul><li>fix(provider): include providerID in SDK cache key (#11020)</li></ul><p>@ideallove:</p><ul><li>fix: maxOutputTokens was accidentally hardcoded to undefined (#10995)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=l(r,[["render",n]]);export{m as __pageData,b as default};
